import { Link, Outlet, useLocation } from 'react-router-dom'
import {
  LayoutDashboard,
  Package,
  ShoppingCart,
  Users,
  Ticket,
  FolderTree,
  Mail,
  LogOut,
  BookOpen,
  MessageSquare,
} from 'lucide-react'
import useAuthStore from '@/stores/useAuthStore'
import { cn } from '@/lib/utils'

export default function AdminLayout() {
  const { logout } = useAuthStore()
  const location = useLocation()

  const links = [
    { to: '/admin', label: 'Dashboard', icon: LayoutDashboard, exact: true },
    { to: '/admin/products', label: 'Produtos', icon: Package },
    { to: '/admin/orders', label: 'Pedidos', icon: ShoppingCart },
    { to: '/admin/users', label: 'Usuários', icon: Users },
    { to: '/admin/coupons', label: 'Cupons', icon: Ticket },
    { to: '/admin/categories', label: 'Categorias', icon: FolderTree },
    { to: '/admin/emails', label: 'E-mails', icon: Mail },
    { to: '/admin/knowledge', label: 'Base de Conhecimento', icon: BookOpen },
    { to: '/admin/conversations', label: 'Conversas IA', icon: MessageSquare },
  ]

  const isActive = (to: string, exact?: boolean) => {
    if (exact) return location.pathname === to
    return location.pathname.startsWith(to)
  }

  return (
    <div className="container mx-auto px-4 py-8 animate-fade-in flex flex-col md:flex-row gap-8 items-start">
      <aside className="w-full md:w-64 shrink-0 md:sticky md:top-28 z-30">
        <nav className="flex md:flex-col gap-1.5 overflow-x-auto pb-4 md:pb-0 custom-scrollbar">
          {links.map((l) => {
            const Icon = l.icon
            const active = isActive(l.to, l.exact)
            return (
              <Link
                key={l.to}
                to={l.to}
                className={cn(
                  'flex items-center gap-3 px-4 py-2.5 rounded-lg whitespace-nowrap font-medium transition-colors',
                  active
                    ? 'bg-primary text-primary-foreground shadow-sm'
                    : 'text-muted-foreground hover:bg-muted hover:text-foreground',
                )}
              >
                <Icon className="w-4 h-4 shrink-0" />
                {l.label}
              </Link>
            )
          })}
          <div className="hidden md:block my-2 border-t border-border mx-2"></div>
          <button
            onClick={logout}
            className="flex items-center gap-3 px-4 py-2.5 rounded-lg whitespace-nowrap font-medium text-destructive hover:bg-destructive/10 transition-colors mt-auto md:mt-0"
          >
            <LogOut className="w-4 h-4 shrink-0" />
            Sair
          </button>
        </nav>
      </aside>

      <main className="flex-1 min-w-0 pb-32 relative z-20 w-full max-w-full">
        <Outlet />
      </main>
    </div>
  )
}
